import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

const Profile = () => {
    const { user, updateUser, logout } = useAuth();
    const [form, setForm] = useState({ name: '', bio: '', avatarUrl: '', password: '' });
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');

    useEffect(() => {
        const fetchProfile = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/users/me');
                const data = res.data.data;
                setForm((prev) => ({
                    ...prev,
                    name: data.name || '',
                    bio: data.bio || '',
                    avatarUrl: data.avatarUrl || ''
                }));
            } catch (err) {
                setError(err.response?.data?.message || 'Failed to load profile');
            }
        };
        fetchProfile();
    }, []);

    const saveProfile = async (e) => {
        e.preventDefault();
        setMessage('');
        setError('');
        try {
            const payload = { ...form };
            if (!payload.password) delete payload.password;
            const res = await axios.put('http://localhost:5000/api/users/me', payload);
            updateUser({ ...user, ...res.data.data });
            setForm((prev) => ({ ...prev, password: '' }));
            setMessage('Profile updated successfully.');
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to update profile');
        }
    };

    const deleteAccount = async () => {
        if (!window.confirm('Are you sure you want to delete your account?')) return;
        try {
            await axios.delete('http://localhost:5000/api/users/me');
            logout();
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to delete account');
        }
    };

    return (
        <div className="container page">
            <div className="page-header">
                <h1>My Profile</h1>
            </div>
            {message && <div className="alert alert-success">{message}</div>}
            {error && <div className="alert alert-error">{error}</div>}
            <div className="card" style={{ maxWidth: 700 }}>
                <form onSubmit={saveProfile}>
                    <div className="form-group">
                        <label>Name</label>
                        <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} />
                    </div>
                    <div className="form-group">
                        <label>Bio</label>
                        <textarea value={form.bio} onChange={(e) => setForm({ ...form, bio: e.target.value })} />
                    </div>
                    <div className="form-group">
                        <label>Avatar URL</label>
                        <input value={form.avatarUrl} onChange={(e) => setForm({ ...form, avatarUrl: e.target.value })} />
                    </div>
                    <div className="form-group">
                        <label>New Password (optional)</label>
                        <input type="password" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} />
                    </div>
                    <button className="btn btn-primary" type="submit">Save Changes</button>
                </form>
                <hr style={{ margin: '24px 0' }} />
                <button className="btn btn-danger" type="button" onClick={deleteAccount}>Delete Account</button>
            </div>
        </div>
    );
};

export default Profile;
